class Solution:
    def minOperations(self, nums1, nums2):
        n = len(nums1)
        best = None
        for mask in range(1 << n):
            a = nums1[:]
            b = nums2[:]
            for i in range(n):
                if mask & (1 << i):
                    a[i], b[i] = b[i], a[i]
            if a[-1] == max(a) and b[-1] == max(b):
                cnt = bin(mask).count('1')
                if best is None or cnt < best:
                    best = cnt
        return best if best is not None else -1

