class Solution:
    def minOperations(self, nums1, nums2):
        n = len(nums1)

        def cost(last1, last2, swapped_last):
            c = 1 if swapped_last else 0
            for i in range(n - 1):
                a, b = nums1[i], nums2[i]
                if a <= last1 and b <= last2:
                    continue
                elif b <= last1 and a <= last2:
                    c += 1
                else:
                    return None
            return c

        options = []
        c1 = cost(nums1[-1], nums2[-1], False)
        if c1 is not None:
            options.append(c1)
        c2 = cost(nums2[-1], nums1[-1], True)
        if c2 is not None:
            options.append(c2)
        return min(options) if options else -1

