var minOperations = function(nums1, nums2) {
    const n = nums1.length;
    const cost = (last1, last2, swappedLast) => {
        let c = swappedLast ? 1 : 0;
        for (let i = 0; i < n - 1; i++) {
            const a = nums1[i], b = nums2[i];
            if (a <= last1 && b <= last2) {
                continue;
            } else if (b <= last1 && a <= last2) {
                c += 1;
            } else {
                return null;
            }
        }
        return c;
    };
    const options = [];
    const c1 = cost(nums1[n - 1], nums2[n - 1], false);
    if (c1 !== null) options.push(c1);
    const c2 = cost(nums2[n - 1], nums1[n - 1], true);
    if (c2 !== null) options.push(c2);
    return options.length ? Math.min(...options) : -1;
};
